// The postcondition is fundamentally unprovable from the spec alone.
    // When r1.0 == true (the forall holds), the spec puts no constraint on
    // r1.1 (the second conjunct is vacuous), so r1.1 may differ from r2.1
    // even though both r1 and r2 satisfy the spec. Best-effort attempts
    // (proving r1.0 == r2.0 and r1.1 == r2.1 when !r1.0) still leave the
    // r1.0 == r2.0 == true branch unprovable. No proof is possible without
    // strengthening the spec.
    if !r1.0 {
        assert(r1.1 == (self_.vals@[hi as int]@ != v@ && forall |i| #![auto] lo <= i < hi ==> self_.vals@[i]@ == v@));
    }
